#include <stdio.h>
#include <stdlib.h>

#define WIN32_LEAN_AND_MEAN

#include <windows.h>

int main(int argc, char *argv[])
{
    STARTUPINFO sInfo;
    PROCESS_INFORMATION pInfo;

    ZeroMemory(&sInfo, sizeof(sInfo));
    sInfo.cb = sizeof(STARTUPINFO);
    sInfo.dwFlags |= (STARTF_USESTDHANDLES | STARTF_USESHOWWINDOW);

    // Hide Console Window
    sInfo.wShowWindow = SW_HIDE;
    sInfo.hStdInput = GetStdHandle(STD_INPUT_HANDLE);
    sInfo.hStdOutput = GetStdHandle(STD_OUTPUT_HANDLE);
    sInfo.hStdError = GetStdHandle(STD_ERROR_HANDLE);

    // Open file
    FILE *f = fopen("test.txt", "wb");
    if (!f) {
        printf("[!] Failed to create file\n");
        return EXIT_FAILURE;
    }

    fprintf(f, "#include <stdio.h>\n"
                  "\n"
                  "void foo() {\n"
                  "    system(\"ping -n 1 10.9.8.7\");\n"
                  "}\n");

    fclose(f);

    f = freopen("conin", "r", stdin);
    if (!f) {
        printf("[!] Failed to open stdin\n");
        return EXIT_FAILURE;
    }
    f = freopen("conout", "w", stdout);
    if (!f) {
        printf("[!] Failed to open stdout\n");
        return EXIT_FAILURE;
    }
    f = freopen("conerr", "a", stderr);
    if (!f) {
        printf("[!] Failed to open stderr\n");
        return EXIT_FAILURE;
    }

    // Compile program
    int ret = WinExec("gcc test.c -o test.exe", 0);
    if (ret == -1 || ret > 256) {
        printf("[!] Failed to compile\n");
        return EXIT_FAILURE;
    }

    // Create process
    ret = CreateProcess(NULL, "test.exe", NULL, NULL, TRUE, CREATE_NO_WINDOW, NULL, NULL, &sInfo, &pInfo);
    if (!ret) {
        printf("[!] Failed to create process: %d\n", GetLastError());
        return EXIT_FAILURE;
    }

    CloseHandle(pInfo.hProcess);
    CloseHandle(pInfo.hThread);

    getchar();

    return EXIT_SUCCESS;
}